example.code:
-- Bad: drop and add in one migration
ALTER TABLE users DROP COLUMN name;
ALTER TABLE users ADD COLUMN full_name VARCHAR(255);

-- Deploy 1: expand
ALTER TABLE users ADD COLUMN full_name VARCHAR(255);
-- (backfill full_name from name)
-- Deploy 2: update app to read full_name
-- Deploy 3: contract
ALTER TABLE users DROP COLUMN name;

users = User.objects.all()
for user in users:
    print(user.orders.count())  # 1 query per user

users = User.objects.prefetch_related('orders').all()
for user in users:
    print(len(user.orders.all()))  # uses prefetched data
